const PREFIX = {
  colors: "--color-",
  fonts: "--font-",
  radii: "--radius-",
  spacing: "--spacing-",
  containers: "--container-",
};

const cssLines = ["/* Generated from .wix/site.json.designTokens. Do not edit. */", ":root {"];
for (const [group, prefix] of Object.entries(PREFIX)) {
  const entries = tokens[group] ?? {};
